class Solution:
    def circularGameLosers(self, n, k):
        pos = 1
        received = {1}
        step = 1
        while True:
            pos = (pos - 1 + step * k) % n + 1
            if pos in received:
                break
            received.add(pos)
            step += 1
        return sorted(set(range(1, n + 1)) - received)

