var circularGameLosers = function(n, k) {
    const visited = new Array(n).fill(false);
    let current = 0;
    visited[0] = true;
    let turn = 1;
    while (true) {
        const nxt = (current + turn * k) % n;
        if (visited[nxt]) break;
        visited[nxt] = true;
        current = nxt;
        turn += 1;
    }
    const losers = [];
    for (let i = 0; i < n; i++) if (!visited[i]) losers.push(i + 1);
    return losers;
};
